const checkpoints = [];

function toDateStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(0, 10);
}

function toTimeStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(11, 16);
}

function compareTime(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

const sessions = JSON.parse(localStorage.getItem('sessions') || '[]');
const prices = JSON.parse(localStorage.getItem('session_ticket_prices') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const startDate = '2026-12-10';
const endDate = '2026-12-20';
const timeFrom = '17:00';
const timeTo = '19:00';

// Sessions that match the Family Night + date/time criteria
const validSessions = sessions.filter((s) => {
  if (!s || s.isActive === false) return false;
  if (s.eventType !== 'family_night' && !s.isFamilyNight) return false;
  const dStr = toDateStr(s.startDateTime);
  if (!dStr || dStr < startDate || dStr > endDate) return false;
  const tStr = toTimeStr(s.startDateTime);
  if (!tStr) return false;
  if (compareTime(tStr, timeFrom) < 0) return false;
  if (compareTime(tStr, timeTo) > 0) return false;
  return true;
});

// Compute adult/child prices and family-of-4 price for each valid session
const sessionPricing = {};
validSessions.forEach((s) => {
  const sessionPrices = prices.filter((p) => p.sessionId === s.id);
  const adult = sessionPrices.filter((p) => p.category === 'adult');
  const child = sessionPrices.filter((p) => p.category === 'child');
  if (!adult.length || !child.length) return;
  const adultPrice = Math.min(...adult.map((p) => p.price));
  const childPrice = Math.min(...child.map((p) => p.price));
  sessionPricing[s.id] = {
    adultPrice,
    childPrice,
    familyPrice: adultPrice * 2 + childPrice * 2
  };
});

const pricedEntries = Object.entries(sessionPricing);
let minFamilyPrice = null;
pricedEntries.forEach(([sid, info]) => {
  if (minFamilyPrice === null || info.familyPrice < minFamilyPrice) {
    minFamilyPrice = info.familyPrice;
  }
});

const cheapestSessionIds = pricedEntries
  .filter(([sid, info]) => info.familyPrice === minFamilyPrice)
  .map(([sid]) => sid);

// Cart items that are 2 adults + 2 children for a valid Family Night session, with correct unit prices
const qualifyingCartItems = cartItems.filter((item) => {
  if (!item || item.itemType !== 'session_ticket') return false;
  const pricing = sessionPricing[item.sessionId];
  if (!pricing) return false;
  const selections = Array.isArray(item.ticketSelections) ? item.ticketSelections : [];
  const adultSel = selections.find((s) => s.category === 'adult');
  const childSel = selections.find((s) => s.category === 'child');
  if (!adultSel || !childSel) return false;
  if (adultSel.quantity !== 2 || childSel.quantity !== 2) return false;
  if (adultSel.unitPrice !== pricing.adultPrice || childSel.unitPrice !== pricing.childPrice) return false;
  const expectedTicketsTotal = pricing.familyPrice;
  if (typeof item.lineTotal === 'number' && item.lineTotal < expectedTicketsTotal) return false;
  return true;
});

// Among those, which are for the cheapest qualifying sessions
const cheapestCartItems = qualifyingCartItems.filter((item) => cheapestSessionIds.includes(item.sessionId));

// CP1 (0.5): User added a correct 2 adult + 2 child Family Night session within the date/time criteria
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.5 });

// CP2 (0.5): The chosen session is one of the cheapest valid options for a family of 4
checkpoints.push({ passed: cheapestCartItems.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function toDateStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(0, 10);
}

function toTimeStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(11, 16);
}

function compareTime(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const itineraries = JSON.parse(localStorage.getItem('itineraries') || '[]');
const itineraryItems = JSON.parse(localStorage.getItem('itinerary_items') || '[]');

const targetDate = '2026-12-18';
const timeStart = '16:00';
const timeEnd = '20:00';

const itinerary = itineraries.find((it) => it && it.date === targetDate) || null;
let hasSanta = false;
let hasLight = false;
let hasCraft = false;

if (itinerary) {
  const itemsForItinerary = itineraryItems.filter((it) => it.itineraryId === itinerary.id);
  const acts = itemsForItinerary
    .map((it) => activities.find((a) => a.id === it.activityId))
    .filter(Boolean);

  function inWindow(act) {
    const dStr = toDateStr(act.startDateTime);
    if (dStr !== targetDate) return false;
    const tStr = toTimeStr(act.startDateTime);
    if (!tStr) return false;
    if (compareTime(tStr, timeStart) < 0) return false;
    if (compareTime(tStr, timeEnd) > 0) return false;
    return true;
  }

  hasSanta = acts.some((a) => {
    if (!a) return false;
    if (a.category !== 'santa_experience') return false;
    if (!(a.audience === 'families' || a.audience === 'all_ages')) return false;
    return inWindow(a);
  });

  hasLight = acts.some((a) => {
    if (!a) return false;
    if (a.category !== 'light_show') return false;
    if (!(a.audience === 'families' || a.audience === 'all_ages')) return false;
    return inWindow(a);
  });

  hasCraft = acts.some((a) => {
    if (!a) return false;
    if (a.category !== 'workshop_craft') return false;
    if (a.locationType !== 'indoor') return false;
    if (!(a.audience === 'families' || a.audience === 'all_ages')) return false;
    return inWindow(a);
  });
}

// CP1 (0.4): Itinerary includes a qualifying Santa experience in the time window
checkpoints.push({ passed: hasSanta, weight: 0.4 });

// CP2 (0.3): Itinerary includes a qualifying light show in the time window
checkpoints.push({ passed: hasLight, weight: 0.3 });

// CP3 (0.3): Itinerary includes a qualifying indoor craft workshop in the time window
checkpoints.push({ passed: hasCraft, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const entrances = JSON.parse(localStorage.getItem('entrances') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

const mainAccessible = entrances.find((e) => e && e.isWheelchairAccessible && e.isMainEntrance);
const entranceNameLower = mainAccessible && typeof mainAccessible.name === 'string'
  ? mainAccessible.name.toLowerCase()
  : null;

const qualifyingMsgExists = messages.some((m) => {
  if (!m) return false;
  if (m.topic !== 'accessibility_mobility') return false;
  if (m.source !== 'accessibility_page') return false;
  if (!m.message || typeof m.message !== 'string') return false;
  const text = m.message.toLowerCase();
  if (entranceNameLower && !text.includes(entranceNameLower)) return false;
  if (!text.includes('wheelchair')) return false;
  if (!text.includes('reserv')) return false; // matches reserve/reservation
  if (!m.name || !m.email) return false;
  if (typeof m.email !== 'string' || !m.email.includes('@')) return false;
  return true;
});

// Single checkpoint (1.0): Correct accessibility inquiry about wheelchair reservation at the main accessible entrance
checkpoints.push({ passed: qualifyingMsgExists, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function toTimeStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(11, 16);
}

function compareTime(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

const sessions = JSON.parse(localStorage.getItem('sessions') || '[]');
const prices = JSON.parse(localStorage.getItem('session_ticket_prices') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find all qualifying Saturday sensory-friendly sessions before 10:00 with child price <= 15
const candidateSessions = sessions.filter((s) => {
  if (!s || s.isActive === false) return false;
  if (s.eventType !== 'sensory_friendly' && !s.isSensoryFriendly) return false;
  const start = new Date(s.startDateTime);
  if (isNaN(start)) return false;
  if (start.getDay() !== 6) return false; // Saturday
  const tStr = toTimeStr(s.startDateTime);
  if (!tStr || compareTime(tStr, '10:00') >= 0) return false;
  const childPrices = prices.filter((p) => p.sessionId === s.id && p.category === 'child');
  if (!childPrices.length) return false;
  const minChildPrice = Math.min(...childPrices.map((p) => p.price));
  if (minChildPrice > 15) return false;
  return true;
});

// Map sessionId -> adult/child price
const priceMap = {};
candidateSessions.forEach((s) => {
  const sessionPrices = prices.filter((p) => p.sessionId === s.id);
  const adult = sessionPrices.filter((p) => p.category === 'adult');
  const child = sessionPrices.filter((p) => p.category === 'child');
  if (!adult.length || !child.length) return;
  const adultPrice = Math.min(...adult.map((p) => p.price));
  const childPrice = Math.min(...child.map((p) => p.price));
  priceMap[s.id] = { adultPrice, childPrice };
});

// Determine earliest qualifying session by startDateTime
let earliestSessionId = null;
let earliestTs = null;
candidateSessions.forEach((s) => {
  if (!priceMap[s.id]) return; // require pricing
  const ts = new Date(s.startDateTime).getTime();
  if (earliestTs === null || ts < earliestTs) {
    earliestTs = ts;
    earliestSessionId = s.id;
  }
});

// Cart items that are 1 adult + 1 child for a qualifying session, correct prices, and no add-ons
const qualifyingItems = cartItems.filter((item) => {
  if (!item || item.itemType !== 'session_ticket') return false;
  const priceInfo = priceMap[item.sessionId];
  if (!priceInfo) return false;
  const selections = Array.isArray(item.ticketSelections) ? item.ticketSelections : [];
  const adultSel = selections.find((s) => s.category === 'adult');
  const childSel = selections.find((s) => s.category === 'child');
  if (!adultSel || !childSel) return false;
  if (adultSel.quantity !== 1 || childSel.quantity !== 1) return false;
  if (adultSel.unitPrice !== priceInfo.adultPrice || childSel.unitPrice !== priceInfo.childPrice) return false;
  const addOnIds = Array.isArray(item.addOnIds) ? item.addOnIds : [];
  if (addOnIds.length !== 0) return false; // user must override defaults to select no add-ons
  const expectedTotal = priceInfo.adultPrice + priceInfo.childPrice;
  if (typeof item.lineTotal === 'number' && item.lineTotal !== expectedTotal) return false;
  return true;
});

const earliestQualifyingItems = qualifyingItems.filter((item) => item.sessionId === earliestSessionId);

// CP1 (0.6): User booked 1 adult + 1 child with correct prices and no add-ons for a qualifying Saturday sensory session
checkpoints.push({ passed: qualifyingItems.length > 0, weight: 0.6 });

// CP2 (0.4): The booking is for the earliest such qualifying session (next available Saturday slot)
checkpoints.push({ passed: !!earliestSessionId && earliestQualifyingItems.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function toTimeStr(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return d.toISOString().substring(11, 16);
}

function compareTime(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

const options = JSON.parse(localStorage.getItem('group_session_options') || '[]');
const bookings = JSON.parse(localStorage.getItem('group_bookings') || '[]');

// Valid group options: Friday, after 20:00, with group discount, and supports pay_on_arrival or invoice_later
const validOptions = options.filter((opt) => {
  if (!opt || opt.isActive === false) return false;
  const start = new Date(opt.startDateTime);
  if (isNaN(start)) return false;
  if (start.getDay() !== 5) return false; // Friday
  const tStr = toTimeStr(opt.startDateTime);
  if (!tStr || compareTime(tStr, '20:00') < 0) return false; // after 8 pm
  const hasDiscount = !!opt.hasGroupDiscount || (Array.isArray(opt.badges) && opt.badges.includes('Group Discount'));
  if (!hasDiscount) return false;
  if (!Array.isArray(opt.paymentMethodsAvailable)) return false;
  const supportsDesiredPayment = opt.paymentMethodsAvailable.includes('pay_on_arrival') || opt.paymentMethodsAvailable.includes('invoice_later');
  if (!supportsDesiredPayment) return false;
  return true;
});

let minPricePerPerson = null;
validOptions.forEach((opt) => {
  if (typeof opt.pricePerPerson === 'number') {
    if (minPricePerPerson === null || opt.pricePerPerson < minPricePerPerson) {
      minPricePerPerson = opt.pricePerPerson;
    }
  }
});

const cheapestOptionIds = validOptions
  .filter((opt) => opt.pricePerPerson === minPricePerPerson)
  .map((opt) => opt.id);

// Group bookings that use a valid option, have groupSize 15, and non-online deferred payment
const qualifyingBookings = bookings.filter((b) => {
  if (!b) return false;
  if (b.groupSize !== 15) return false;
  if (b.paymentMethod !== 'pay_on_arrival' && b.paymentMethod !== 'invoice_later') return false;
  const opt = options.find((o) => o.id === b.groupSessionOptionId);
  if (!opt) return false;
  const isValidOpt = validOptions.some((vo) => vo.id === opt.id);
  if (!isValidOpt) return false;
  return true;
});

const bestDealBookings = qualifyingBookings.filter((b) => cheapestOptionIds.includes(b.groupSessionOptionId));

// CP1 (0.6): User created a qualifying group booking (15 guests, Friday after 8 pm, group discount, deferred payment)
checkpoints.push({ passed: qualifyingBookings.length > 0, weight: 0.6 });

// CP2 (0.4): The booking uses the cheapest valid group option by price per person
checkpoints.push({ passed: bestDealBookings.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

const qualifyingSubs = subs.filter((s) => {
  if (!s) return false;
  if (s.frequency !== 'weekly') return false;
  if (!Array.isArray(s.interests)) return false;
  const hasFamily = s.interests.includes('family_activities');
  const hasOffers = s.interests.includes('special_offers_discounts');
  if (!hasFamily || !hasOffers) return false;
  const extra = s.interests.filter((id) => id !== 'family_activities' && id !== 'special_offers_discounts');
  if (extra.length > 0) return false; // must select only these two interests
  if (!s.email || typeof s.email !== 'string' || !s.email.includes('@')) return false;
  return true;
});

// Single checkpoint (1.0): Correct weekly subscription with only the two required interest categories
checkpoints.push({ passed: qualifyingSubs.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const ticketTypes = JSON.parse(localStorage.getItem('ticket_types') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Identify one standard and one upgraded (includesFreeDrink) candidate
const standardCandidates = ticketTypes.filter((t) => t && t.status === 'active' && t.ticketCategory === 'standard' && typeof t.adultPrice === 'number');
const upgradedCandidates = ticketTypes.filter((t) => t && t.status === 'active' && t.includesFreeDrink && typeof t.adultPrice === 'number');

const standard = standardCandidates.reduce((best, t) => (!best || t.adultPrice < best.adultPrice ? t : best), null);
const upgraded = upgradedCandidates.reduce((best, t) => (!best || t.adultPrice < best.adultPrice ? t : best), null);

const maxTotal = 120;
let expectedChoice = null;

if (upgraded && upgraded.adultPrice * 2 <= maxTotal) {
  // Prefer upgraded option with complimentary drink if under cap
  expectedChoice = upgraded;
} else if (standard && standard.adultPrice * 2 <= maxTotal) {
  // Fallback to cheaper option under the cap
  expectedChoice = standard;
}

function isCartItemValidForTicket(cartItem, ticket) {
  if (!ticket) return false;
  if (!cartItem || cartItem.itemType !== 'ticket_type') return false;
  if (cartItem.ticketTypeId !== ticket.id) return false;
  const selections = Array.isArray(cartItem.ticketSelections) ? cartItem.ticketSelections : [];
  const adultSel = selections.find((s) => s.category === 'adult');
  if (!adultSel) return false;
  if (adultSel.quantity !== 2) return false;
  if (adultSel.unitPrice !== ticket.adultPrice) return false;
  const otherWithQty = selections.find((s) => s.category !== 'adult' && s.quantity > 0);
  if (otherWithQty) return false;
  const expectedTotal = ticket.adultPrice * 2;
  if (typeof cartItem.lineTotal === 'number' && cartItem.lineTotal !== expectedTotal) return false;
  if (expectedTotal > maxTotal) return false;
  return true;
}

const validStandardItems = cartItems.filter((ci) => isCartItemValidForTicket(ci, standard));
const validUpgradedItems = cartItems.filter((ci) => isCartItemValidForTicket(ci, upgraded));
const validAny = validStandardItems.concat(validUpgradedItems);

let expectedItems = [];
if (expectedChoice) {
  expectedItems = cartItems.filter((ci) => isCartItemValidForTicket(ci, expectedChoice));
}

// CP1 (0.7): User added two adult tickets under the $120 cap for either the standard or upgraded candidate
checkpoints.push({ passed: validAny.length > 0, weight: 0.7 });

// CP2 (0.3): User chose the correct ticket type according to the free-drink preference and price cap logic
checkpoints.push({ passed: !!expectedChoice && expectedItems.length > 0, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkoints = [];

function compareTime(a, b) {
  if (!a || !b) return 0;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

const routes = JSON.parse(localStorage.getItem('transit_routes') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Candidate bus routes: walkingTime <= 10 and serviceEndTime >= 22:00
const candidateRoutes = routes.filter((r) => {
  if (!r || r.mode !== 'bus') return false;
  if (typeof r.walkingTimeMinutes !== 'number' || r.walkingTimeMinutes > 10) return false;
  if (!r.serviceEndTime) return false;
  if (compareTime(r.serviceEndTime, '22:00') < 0) return false;
  return true;
});

const qualifyingMessages = messages.filter((m) => {
  if (!m) return false;
  if (m.topic !== 'transportation_parking') return false;
  if (m.source !== 'contact_page') return false;
  if (!m.message || typeof m.message !== 'string') return false;
  const text = m.message.toLowerCase();
  const mentionsRoute = candidateRoutes.some((r) => {
    if (!r || !r.name) return false;
    return text.includes(r.name.toLowerCase());
  });
  if (!mentionsRoute) return false;
  if (!text.includes('last')) return false;
  if (!text.includes('depart')) return false; // matches departure/departing
  if (!m.name || !m.email) return false;
  if (typeof m.email !== 'string' || !m.email.includes('@')) return false;
  return true;
});

// Single checkpoint (1.0): Correct transportation/parking inquiry about last departure time for a qualifying bus route
checkoints.push({ passed: qualifyingMessages.length > 0, weight: 1.0 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
